import{c as a,Q as t,j as r,m as n}from"./chunks/framework.BXc4yaFE.js";const u=JSON.parse('{"title":"TheSequence — 2026-04-19","description":"","frontmatter":{"title":"TheSequence — 2026-04-19","date":"2026-04-19T00:00:00.000Z","source":"TheSequence","type":"ai-news"},"headers":[],"relativePath":"research/ai-news/2026-04/2026-04-19-thesequence.md","filePath":"research/ai-news/2026-04/2026-04-19-thesequence.md","lastUpdated":1779894392000}'),i={name:"research/ai-news/2026-04/2026-04-19-thesequence.md"};function o(s,e,l,c,h,p){return t(),r("div",null,[...e[0]||(e[0]=[n('<h1 id="🔢-thesequence-—-2026-04-19" tabindex="-1">🔢 TheSequence — 2026-04-19 <a class="header-anchor" href="#🔢-thesequence-—-2026-04-19" aria-label="Permalink to &quot;🔢 TheSequence — 2026-04-19&quot;">​</a></h1><blockquote><p>165k+ 訂閱；ML / 企業 AI 應用週報，Jesus Rodriguez 主筆 來源：<a href="https://thesequence.substack.com/feed" target="_blank" rel="noreferrer">TheSequence</a></p></blockquote><hr><h2 id="the-sequence-radar-845-last-week-in-ai-anthropic-and-openai-enter-a-new-phase" tabindex="-1"><a href="https://thesequence.substack.com/p/the-sequence-radar-845-last-week" target="_blank" rel="noreferrer">The Sequence Radar #845: Last Week in AI: Anthropic and OpenAI Enter a New Phase</a> <a class="header-anchor" href="#the-sequence-radar-845-last-week-in-ai-anthropic-and-openai-enter-a-new-phase" aria-label="Permalink to &quot;[The Sequence Radar #845: Last Week in AI: Anthropic and OpenAI Enter a New Phase](https://thesequence.substack.com/p/the-sequence-radar-845-last-week)&quot;">​</a></h2><p><em>🔢 TheSequence | 2026-04-19</em></p><p>Next Week in The Sequence:</p><p>We start a new series about alternatives to transformers including text diffusion models, SSMs and many more.</p><p>The opinion installment will discuss a hot topic: MCP or CLIs?</p><p>The AI of the week section dives into Claude Opus 4.7.</p><p>Subscribe and don’t miss out:</p><p>📝 Editorial: Last Week in AI: Anthropic and OpenAI Enter a New Phase</p><p>This week brought a particularly interesting cluster of releases from Anthropic and OpenAI. Anthropic pushed on both the model and product fronts with Claude Opus 4.7 and the new Claude Design, while OpenAI expanded in two different directions with GPT-Rosalind and the latest Codex. Put together, these launches say something important about where the frontier is heading. The story is no longer just about smarter chatbots. It is about AI splitting into distinct product forms: the general-purpose reasoning model, the domain specialist, and the workflow-native agent.</p><p>Anthropic’s side of the week was especially revealing because it showed both ends of that transition. Claude Opus 4.7 looks like a refinement of the frontier generalist: stronger for advanced software work, better at following instructions, and more reliable in longer chains of reasoning. But Claude Design is the more interesting signal. It packages Claude not just as a model that can describe visual work, but as a collaborator for actually producing it—designs, prototypes, slides, and one-pagers. That matters because it turns design from a prompting exercise into a workflow. Anthropic is not just improving a model; it is carving out a new interface category where reasoning and visual production start to merge.</p><p>OpenAI’s releases tell a parallel story, but from a different angle. GPT-Rosalind represents the rise of the specialist model: a system built specifically for biology, drug discovery, and translational medicine rather than a general model stretched into a scientific costume. That is a meaningful shift. The next wave of AI advantage will not come only from one model doing everything reasonably well. It will come from systems that are deeply adapted to the language, tools, and constraints of high-value domains. Rosalind suggests that science is becoming one of the first places where that specialization is explicit, productized, and strategically central.</p><p>Then there is Codex, which may be the clearest signal of all. The newest version is not just about code generation. It can operate a computer, use tools and apps, remember preferences, connect to remote environments, and handle ongoing work over time. That changes the meaning of “coding assistant.” Codex is inching toward something broader: an agentic operating layer for software and knowledge work. The important shift is not that it writes better code. It is that it increasingly participates in the surrounding workflow—browsing, coordinating, iterating, and executing across environments rather than waiting passively for the next prompt.</p><p>The deeper pattern across Anthropic and OpenAI is that frontier AI is fragmenting into real products. Anthropic is pushing the frontier generalist into adjacent creative workflows. OpenAI is pushing both specialization and agentic execution. And together they are making the competitive landscape much more interesting. The real race is no longer just who has the smartest model on a benchmark. It is who can turn intelligence into the most compelling system for actual work. That is what made this week’s releases worth watching.</p><p>🔎 AI Research</p><p><a href="https://arxiv.org/html/2604.11035v1" target="_blank" rel="noreferrer">Introspective Diffusion Language Models </a></p><p>AI Lab: Together AI, University of Illinois Urbana-Champaign, The University of Texas at Austin, Princeton University, and Stanford University</p><p>Summary: Diffusion language models traditionally lag behind autoregressive models because they lack introspective consistency, meaning they do not reliably agree with their own generated tokens. To address this, the authors introduce the Introspective Diffusion Language Model (I-DLM), which utilizes a novel strided decoding algorithm to simultaneously verify and generate tokens, matching autoregressive model quality while significantly improving serving efficiency.</p><p><a href="https://arxiv.org/html/2604.08706v1" target="_blank" rel="noreferrer">Efficient RL Training for LLMs with Experience Replay </a></p><p>AI Lab: FAIR at Meta and NYU Courant Institute and CDS</p><p>Summary: This paper challenges the prevailing assumption that large language model reinforcement learning requires strictly fresh, on-policy data by demonstrating the effectiveness of experience replay. Through a systematic study, the authors show that a well-designed replay buffer can drastically reduce expensive inference compute costs during training while maintaining or even improving the model’s final performance and output diversity.</p><p><a href="https://arxiv.org/html/2604.13036v1" target="_blank" rel="noreferrer">Lyra 2.0: Explorable Generative 3D Worlds </a></p><p>AI Lab: NVIDIA</p><p>Summary: Generating large-scale 3D scenes using video diffusion models often suffers from spatial forgetting and temporal drifting over long camera trajectories. Lyra 2.0 mitigates these degradations by utilizing per-frame 3D geometry for history retrieval and self-augmented training to correct drift, enabling the creation of persistent, explorable 3D worlds from a single input image.</p><p><a href="https://arxiv.org/html/2604.12946v1" target="_blank" rel="noreferrer">Parcae: Scaling Laws For Stable Looped Language Models</a></p><p>AI Lab: University of California, San Diego and Together AI,</p><p>Summary: Looped architectures offer a way to increase a model’s compute without increasing its parameter footprint by repeatedly passing activations through a block of layers, but existing training methods for these models are often unstable. To resolve this, the authors propose Parcae, a novel, stable looped architecture that constrains the spectral norm of its injection parameters, enabling the discovery of predictable scaling laws for both training and test-time compute that improve model quality while keeping parameter counts fixed.</p><p><a href="https://arxiv.org/html/2604.09168v2" target="_blank" rel="noreferrer">ELT: Elastic Looped Transformers for Visual Generation </a></p><p>AI Lab: Google DeepMind</p><p>Summary: Conventional visual generative models rely on deep stacks of unique transformer layers, whereas this paper proposes Elastic Looped Transformers (ELT) that use iterative, weight-shared blocks to drastically reduce parameter counts. By utilizing an Intra-Loop Self Distillation (ILSD) training method, ELT achieves high-fidelity image and video generation while enabling Any-Time inference, allowing users to dynamically trade off computational cost and generation quality at test-time.</p><p><a href="https://arxiv.org/html/2604.09443v3" target="_blank" rel="noreferrer">Many-Tier Instruction Hierarchy in LLM Agents </a></p><p>AI Lab: Johns Hopkins University</p><p>Summary: Current instruction hierarchy paradigms use a small, fixed set of privilege levels, which is inadequate for real-world agents receiving conflicting instructions from numerous heterogeneous sources. To address this limitation, the authors introduce the Many-Tier Instruction Hierarchy (ManyIH) and an accompanying benchmark, MANYIH-BENCH, revealing that current frontier models perform poorly when resolving conflicts across arbitrarily many privilege levels.</p><p>🤖 AI Tech Releases</p><p>GPT-Rosalind</p><p>OpenAI <a href="https://openai.com/index/introducing-gpt-rosalind/" target="_blank" rel="noreferrer">released GPT-Rosalind</a>, a new frontier reasoning model for life science research.</p><p>Gemini on Mac</p><p>Google <a href="https://blog.google/innovation-and-ai/products/gemini-app/gemini-app-now-on-mac-os/" target="_blank" rel="noreferrer">announced a release </a>of the Gemini app for macOS.</p><p>Codex for (Almost) Everything</p><p>OpenAI unveiled <a href="https://openai.com/index/codex-for-almost-everything/" target="_blank" rel="noreferrer">Codex for (almost) everything</a>, a new agents that extends</p><p>Chrome Skills</p><p>Google <a href="https://blog.google/products-and-platforms/products/chrome/skills-in-chrome/" target="_blank" rel="noreferrer">released Chrome Skills </a>to integrate AI workflows.</p><p>Claude Design</p><p>Anthropic Labs <a href="https://www.anthropic.com/news/claude-design-anthropic-labs" target="_blank" rel="noreferrer">unveiled Claude Design</a>, a collaborative experience to create visual artifacts.</p><p>Qwen3.6-35B-A3B</p><p>Alibaba Qwen <a href="https://qwen.ai/blog?id=qwen3.6-35b-a3b" target="_blank" rel="noreferrer">open sourced Qwen3.6-35B-A3B</a>, a more efficient version of its marquee agentic coding model.</p><p>📡AI News You Need to Know About</p><p><a href="https://www.bloomberg.com/news/articles/2026-04-17/ai-coding-startup-cursor-in-talks-to-raise-2-billion-in-funding" target="_blank" rel="noreferrer">Cursor in talks at $50B valuation</a> — Four-year-old Cursor is nearing a $2B+ round led by returning backers Thrive and a16z at a $50B pre-money valuation (with Battery and Nvidia also expected to participate), as it projects ending 2026 at a $6B+ ARR run rate.</p><p><a href="https://x.com/kevinweil/status/2045230426210648348" target="_blank" rel="noreferrer">OpenAI’s former product chief and Sora head leave</a><a href="https://x.com/kevinweil/status/2045230426210648348" target="_blank" rel="noreferrer"></a>— Kevin Weil (ex-CPO, most recently running the OpenAI for Science team, which is being decentralized into other research groups) and Bill Peebles (the researcher behind Sora) both announced their departures on Friday as OpenAI sheds “side quests” to focus on enterprise AI and its forthcoming superapp — with enterprise CTO Srinivas Narayanan reportedly leaving as well.</p><p><a href="https://www.cnbc.com/2026/04/17/cerebras-new-ipo-ai-chips.html" target="_blank" rel="noreferrer">Cerebras files publicly for US IPO (second attempt)</a><a href="https://www.cnbc.com/2026/04/17/cerebras-new-ipo-ai-chips.html" target="_blank" rel="noreferrer"></a>— AI chipmaker Cerebras Systems publicly filed its S-1 with the SEC on Friday, disclosing $510M in 2025 revenue and $87.9M of net income (vs. a $484.8M loss on $290M of revenue in 2024), and plans to list on Nasdaq as “CBRS” with Morgan Stanley, Citi, Barclays, and UBS leading the offering.</p><p><a href="https://factory.ai/news/series-c" target="_blank" rel="noreferrer">Factory hits $1.5B valuation</a> — Enterprise AI coding startup Factory raised a $150M Series C led by Khosla Ventures at a $1.5B valuation, adding Keith Rabois to its board and bringing customers like Morgan Stanley, EY, and Palo Alto Networks onto its “Droids” agent platform.</p><p><a href="https://www.bloomberg.com/news/articles/2026-04-16/tiger-global-backed-upscale-ai-in-talks-for-2-billion-valuation" target="_blank" rel="noreferrer">Upscale AI at $2B valuation</a><a href="https://www.bloomberg.com/news/articles/2026-04-16/tiger-global-backed-upscale-ai-in-talks-for-2-billion-valuation" target="_blank" rel="noreferrer"></a>— Seven-month-old AI infrastructure startup Upscale AI is reportedly in talks to raise $180M–$200M at a ~$2B valuation, its third round since launching, with Tiger Global, Xora, and Premji Invest as existing backers despite no shipped product yet.</p><p><a href="https://techcrunch.com/2026/04/15/hightouch-reaches-100m-arr-fueled-by-marketing-tools-powered-by-ai/" target="_blank" rel="noreferrer">Hightouch hits $100M ARR</a><a href="https://techcrunch.com/2026/04/15/hightouch-reaches-100m-arr-fueled-by-marketing-tools-powered-by-ai/" target="_blank" rel="noreferrer"></a>— Hightouch told TechCrunch it has reached $100M ARR — $70M of which came in the 20 months since launching its brand-aware AI marketing product used by Domino’s, Chime, PetSmart, and Spotify. → TechCrunch exclusive; no earlier original source found.</p><p><a href="https://www.prnewswire.com/news-releases/gitar-launches-from-stealth-with-9m-as-ai-generated-code-outpaces-teams-ability-to-validate-and-ship-software-safely-302743190.html" target="_blank" rel="noreferrer">Gitar exits stealth with $9M</a><a href="https://www.prnewswire.com/news-releases/gitar-launches-from-stealth-with-9m-as-ai-generated-code-outpaces-teams-ability-to-validate-and-ship-software-safely-302743190.html" target="_blank" rel="noreferrer"></a>— Gitar, founded by ex-Uber/Google/Intel engineers Ali-Reza Adl-Tabatabai and Gautam Korlam, emerged from stealth with a $9M seed led by Venrock (with Sierra Ventures) to build AI “agentic quality gates” for code review and CI validation.</p><p><a href="https://www.cnbc.com/2026/04/16/tsmc-q1-profit-58-percent-ai-chip-demand-record.html" target="_blank" rel="noreferrer">TSMC Q1 profit beats estimates</a> — TSMC reported Q1 2026 net income of NT$572.5B (up 58% YoY) on revenue of US$35.9B (up 40.6% YoY in USD terms), guided full-year revenue growth above 30%, and said Middle East conflict has not dented AI chip demand.</p><p><a href="https://thenextweb.com/news/accel-5-billion-fund-ai-anthropic-cursor-venture-capital" target="_blank" rel="noreferrer">Accel raises $5B for late-stage AI bets</a><a href="https://thenextweb.com/news/accel-5-billion-fund-ai-anthropic-cursor-venture-capital" target="_blank" rel="noreferrer"></a>— Accel announced $5B in fresh capital — $4B for its fifth Leaders Fund (targeting 20–25 ~$200M late-stage checks in AI, robotics, defense, and data center infrastructure) plus a $650M LP sidecar — after Anthropic and Cursor marks soared.</p><p><a href="https://www.coreweave.com/news/jane-street-signs-6-billion-ai-cloud-agreement-with-coreweave" target="_blank" rel="noreferrer">Jane Street invests $1B in CoreWeave, commits $6B in cloud spend</a><a href="https://www.coreweave.com/news/jane-street-signs-6-billion-ai-cloud-agreement-with-coreweave" target="_blank" rel="noreferrer"></a>— Jane Street committed ~$6B to use CoreWeave’s AI cloud (including NVIDIA Vera Rubin capacity) and separately bought $1B of Class A stock at $109/share, bringing total commitments to $7B.</p><hr>',60)])])}const g=a(i,[["render",o]]);export{u as __pageData,g as default};
